INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'basic',
  '108 Foxcroft Lane — Date of Death Valuation',
  'You are appraising a home at 108 Foxcroft Lane, Greenville SC for an estate settlement and federal estate tax filing, on referral from Palmetto Trust & Estate Services. The retrospective effective date is the date of death, 14 months prior to today. The subject is an 1,820 SF home built in 1998 with three bedrooms, two full bathrooms, and a 2-car garage, in good condition. Your role is to develop an independent opinion of Fair Market Value as defined by IRS Revenue Ruling 59-60 — the price at which property would change hands between a willing buyer and a willing seller, neither under any compulsion to buy or sell, and both having reasonable knowledge of relevant facts.

Three closed sales are provided, all confirmed within 6 months of the date of death. Two require GLA adjustments (one larger, one smaller than the subject) and one requires a bathroom adjustment. A teaching point at this level: both cost indications fall BELOW the paired sales range — cost acts as a floor rather than a ceiling. The market is paying above depreciated replacement cost for this 1998 vintage. Identify the differing features, derive market-supported adjustment values, apply them, and reconcile the adjusted prices into your Fair Market Value opinion as of the date of death. The opinion will be reported on IRS Form 706 and may be reviewed by the IRS.'
FROM scenario_categories WHERE code = 'M2-S4-C3';

INSERT INTO model_answers
