  '{"subject": {"address": "318 Clover Ridge Court, Greer SC 29651", "context": "Pre-Purchase Advisory · Fee Engagement · Upstate Investment Partners · No Contract Price", "difficulty": "Basic", "fact_sheet": [["GLA", "1,780 SF"], ["Bathrooms", "2 full"], ["Bedrooms", "3"], ["Garage", "2-car"], ["Year Built", "2003"], ["Condition", "Good"]]}, "comps": [{"id": "C1", "label": "Comp 1", "price": 268000, "fact_sheet": {"Sale Price": "$268,000", "Sale Date": "2 mos. ago", "GLA": "1,930 SF", "Bathrooms": "2 full", "Bedrooms": "3", "Garage": "2-car", "Year Built": "2003", "Condition": "Good"}}, {"id": "C2", "label": "Comp 2", "price": 264500, "fact_sheet": {"Sale Price": "$264,500", "Sale Date": "1 mo. ago", "GLA": "1,780 SF", "Bathrooms": "2.5", "Bedrooms": "3", "Garage": "2-car", "Year Built": "2004", "Condition": "Good"}}, {"id": "C3", "label": "Comp 3", "price": 251000, "fact_sheet": {"Sale Price": "$251,000", "Sale Date": "3 mos. ago", "GLA": "1,660 SF", "Bathrooms": "2 full", "Bedrooms": "3", "Garage": "2-car", "Year Built": "2002", "Condition": "Good"}}], "features": [{"key": "gla", "label": "GLA", "unit_label": "$/SF", "step3_kind": "per_unit", "subject_units": 1780, "comp_units": {"C1": 1930, "C2": 1780, "C3": 1660}}, {"key": "bath", "label": "Bathrooms", "unit_label": "$", "step3_kind": "lump_sum"}], "step1_grid": [{"label": "Sale Price", "subject": "N/A", "comp_values": {"C1": "$268,000", "C2": "$264,500", "C3": "$251,000"}, "diff_comps": []}, {"label": "Sale Date", "subject": "Current", "comp_values": {"C1": "2 mos. ago", "C2": "1 mo. ago", "C3": "3 mos. ago"}, "diff_comps": []}, {"label": "GLA", "subject": "1,780 SF", "comp_values": {"C1": "1,930 SF", "C2": "1,780 SF", "C3": "1,660 SF"}, "feature_key": "gla", "diff_comps": ["C1", "C3"], "diff_directions": {"C1": "superior", "C3": "inferior"}}, {"label": "Bathrooms", "subject": "2 full", "comp_values": {"C1": "2 full", "C2": "2.5", "C3": "2 full"}, "feature_key": "bath", "diff_comps": ["C2"], "diff_directions": {"C2": "superior"}}, {"label": "Bedrooms", "subject": "3", "comp_values": {"C1": "3", "C2": "3", "C3": "3"}, "diff_comps": []}, {"label": "Garage", "subject": "2-car", "comp_values": {"C1": "2-car", "C2": "2-car", "C3": "2-car"}, "diff_comps": []}, {"label": "Year Built", "subject": "2003", "comp_values": {"C1": "2003", "C2": "2004", "C3": "2002"}, "diff_comps": []}, {"label": "Condition", "subject": "Good", "comp_values": {"C1": "Good", "C2": "Good", "C3": "Good"}, "diff_comps": []}], "step2": {"tabs": [{"key": "paired", "label": "Paired Sales Analysis", "intro": "Use the supporting market data to derive contributory values. Two paired sales tables — one per adjustment type. In a consulting engagement, the same analytical standards apply: the investor client deserves the same quality of support as a lender or court.", "tables": [{"kind": "paired_dollar_per_unit", "feature_key": "gla", "title": "GLA Pairs — Calculate $/SF", "instruction": "Current-market pairs confirmed equivalent except GLA. Divide Price Difference ÷ SF Difference. Pairs are consistent — clean market support.", "input_label": "Your $/SF", "input_suffix": "/SF", "rows": [{"label": "1", "cells": ["1,630 SF / $242,000", "1,780 SF / $249,000", "150 SF", "$7,000"]}, {"label": "2", "cells": ["1,680 SF / $246,500", "1,830 SF / $253,700", "150 SF", "$7,200"]}, {"label": "3", "cells": ["1,720 SF / $250,000", "1,870 SF / $257,400", "150 SF", "$7,400"]}], "column_headers": ["Pair", "Sale A (SF / Price)", "Sale B (SF / Price)", "SF Diff", "Price Diff"], "concluded_label": "Concluded GLA Adjustment", "concluded_helper": "Bracket your three results — pairs cluster tightly."}, {"kind": "paired_dollar_diff", "feature_key": "bath", "title": "Bathroom Pairs — 2 Full vs. 2.5 Baths", "instruction": "Pairs isolate the bathroom count difference. Subtract the 2-full-bath sale price from the 2.5-bath sale price.", "input_label": "Your Price Difference", "input_suffix": "", "rows": [{"label": "1", "cells": ["$248,000", "$254,200"]}, {"label": "2", "cells": ["$252,500", "$258,900"]}], "column_headers": ["Pair", "2 Full Bath Sale", "2.5 Bath Sale"], "concluded_label": "Concluded Bathroom Adjustment", "concluded_helper": "Bracket your two results."}]}, {"key": "cost", "label": "Cost-Based Support", "intro": "Calculate the depreciated contributory value for both adjustment types. Both cost indications fall at or near the top of the paired sales range — a mild ceiling in both cases. Methods are well-aligned, providing convergent support for the advisory conclusion.", "items": [{"kind": "cost_calc", "feature_key": "gla", "title": "GLA Contributory Value ($/SF)", "fact_rows": [["RCN", "$76.00 / SF"], ["Effective Age", "21 years"], ["Economic Life", "60 years"], ["Depreciation Rate", "21 ÷ 60 = 35%"], ["Formula", "$76.00 × (1 − 0.35) = ?"]], "input_suffix": "/SF"}, {"kind": "cost_calc", "feature_key": "bath", "title": "Bathroom Cost (Half-Bath Addition)", "fact_rows": [["Cost to Add Half Bath", "$10,000"], ["Effective Age", "21 years"], ["Economic Life", "60 years"], ["Depreciation Rate", "35%"], ["Formula", "$10,000 × (1 − 0.35) = ?"]], "input_suffix": ""}]}], "reconciliation": {"instruction": "Review both method indications and enter your reconciled adjustment for each item. Both cost indications are at or near the top of the paired sales range. Weight paired sales; cost confirms the upper boundary.", "items": [{"feature_key": "gla", "label": "GLA Adjustment ($/SF)"}, {"feature_key": "bath", "label": "Bathroom Adjustment ($)"}]}}, "step3": {"instruction": "Apply your reconciled adjustments to each comparable. Use a NEGATIVE value where the comp is superior to the subject, and a POSITIVE value where it is inferior. In an advisory context, the rationale should help the investor client understand the market evidence behind each adjustment — explain what the market pays and why, not just cite methodology.", "applicable": {"C1": ["gla"], "C2": ["bath"], "C3": ["gla"]}, "method_dropdown": ["Paired Sales Analysis", "Grouped Paired Sales", "Cost-Based Support", "Income Differential / GRM", "Regression Analysis", "Appraiser Judgment / Extraction"], "support_min_chars": 15}, "step4": {"show_net_gross_panel": false}}'::jsonb,
  '{"step1_correct_flags": {"C1": ["gla"], "C2": ["bath"], "C3": ["gla"]}, "step1_rationale": "Comp 1 is 150 SF larger than the subject (superior GLA, requires negative adjustment). Comp 2 has 2.5 bathrooms versus the subject''s 2 full (superior, requires negative adjustment). Comp 3 is 120 SF smaller than the subject (inferior GLA, requires positive adjustment). All other features (bedrooms, garage, year built, condition) are equivalent across all three comparables. Sale dates are within 3 months — no market conditions adjustment required at this level.", "step2_tables": {"paired": {"gla": {"pair_answers": [46.67, 48.0, 49.33], "concluded_range": [46.5, 49.5], "rationale": "Three pairs produce $46.67, $48.00, and $49.33/SF — a tight $2.67 spread that constitutes strong, consistent market support. Reconcile near the midpoint."}, "bath": {"pair_answers": [6200, 6400], "concluded_range": [6150, 6450], "rationale": "Two pairs bracket the half-bath increment at $6,200 and $6,400 — tight market support."}}, "cost": {"gla": {"answer": 49.4, "rationale": "$76.00 × (1 − 0.35) = $49.40/SF. Sits near the top of the paired sales range ($46.67–$49.33/SF). Methods converge — mild ceiling, strong advisory support."}, "bath": {"answer": 6500, "rationale": "$10,000 × (1 − 0.35) = $6,500. Sits just above the paired sales range ($6,200–$6,400) — a mild ceiling. Conclude toward paired sales."}}}, "step2_reconciliation": {"gla": {"range": [47.0, 49.0], "rationale": "Paired sales support $46.67–$49.33/SF (three tightly clustered pairs). Cost support of $49.40/SF sits at the top of the range — a mild ceiling. The methods are well-aligned, providing convergent support for the advisory conclusion. Reconcile near the midpoint at approximately $48/SF."}, "bath": {"range": [6200, 6400], "rationale": "Paired sales bracket $6,200–$6,400. Cost support of $6,500 sits just above — a mild ceiling. Reconcile within the paired bracket."}}, "step3_adjustments": {"C1": {"gla": {"direction": "negative", "amount_per_unit": -48.0, "units": 150, "computed_amount": -7200, "method": "Paired Sales Analysis", "rationale": "Comp 1 is 150 SF larger than the subject (superior). At the reconciled rate of $48/SF (drawn from three tightly-clustered current-market pairs), the GLA adjustment is −$7,200. The market consistently pays in the $47–$49/SF range for additional GLA at this price point and vintage — useful information for the investor''s pricing strategy."}}, "C2": {"bath": {"direction": "negative", "amount": -6300, "method": "Paired Sales Analysis", "rationale": "Comp 2 has 2.5 bathrooms versus the subject''s 2 full (superior). The half-bath increment from two paired sales is approximately $6,300 (midpoint of $6,200–$6,400). Cost support of $6,500 confirms the range without overriding it."}}, "C3": {"gla": {"direction": "positive", "amount_per_unit": 48.0, "units": 120, "computed_amount": 5760, "method": "Paired Sales Analysis", "rationale": "Comp 3 is 120 SF smaller than the subject (inferior). At the reconciled rate of $48/SF, the GLA adjustment is +$5,760. The market reaction is symmetrical — the same $48/SF that buyers pay for additional GLA, they discount for less."}}}, "step4_adjusted_prices": {"C1": {"unadjusted": 268000, "adjusted": 260800}, "C2": {"unadjusted": 264500, "adjusted": 258200}, "C3": {"unadjusted": 251000, "adjusted": 256760}}, "step4_reconciliation_narrative": "Adjusted prices cluster in a tight band of approximately $256,760–$260,800 — a spread of roughly $4,000. The advisory opinion of market value is well-supported in the $258,000–$261,000 range. The investor may use this range to evaluate the asking price, establish an opening offer, or set a walk-away threshold. The defining feature of the private consulting context is the absence of an external regulatory audience — there is no lender requiring USPAP compliance for loan purposes, no court applying Daubert standards, no IRS reviewing documentation. The client is an investor making a business decision, and the appraiser''s obligation is to that client: an independent, well-supported advisory opinion that accurately reflects current market value. The analytical process is identical to regulated assignments; what changes is the framing and documentation style. Both cost indications in this scenario fall at or near the top of the paired sales range, providing convergent support without clearly acting as either floor or ceiling. This is the most common relationship between the two methods and reinforces that each case must be evaluated on its own merits.", "tolerance_note": "Student answers are accepted within ±5% of model derived values for paired-sales calculations and within the indicated reconciliation range. Step 3 adjustments accepted within ±13% of the computed amount for GLA and ±12% for bath."}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'adjustment_grid'
WHERE sc.code = 'M2-S4-C4'
  AND s.order_index = 1;

-- ─────────────────────────────────────────────────────
-- Scenario: 1847 Fieldstone Way — Portfolio Acquisition Advisory
-- Category M2-S4-C4 #2 · difficulty 'intermediate'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 2,
  'intermediate',
  '1847 Fieldstone Way — Portfolio Acquisition Advisory',
  'You are appraising a home at 1847 Fieldstone Way, Simpsonville SC for a fee advisory engagement on behalf of Piedmont Capital Group. The client is evaluating this property as a potential addition to a residential rental portfolio. The advisory opinion informs the acquisition decision — specifically whether the asking price reflects current market value and what a defensible offer range looks like. There is no contract price, no lender, no court — the advisory opinion is the pricing anchor.

The subject is a 2,020 SF home built in 2008 with three bedrooms, 2.5 bathrooms, and a 2-car garage, in good condition. Three closed sales are provided. They differ from the subject across three adjustment types: GLA, bathrooms, and market conditions (one comparable sold 9 months ago). Two analytical challenges are introduced at this level. First, the GLA paired sales include a divergent pair that must be identified and addressed before drawing a conclusion — a sophisticated investor will ask why the outlier was excluded and needs a credible answer. Second, both cost indications significantly exceed paired sales — both acting as ceilings — so the gap is large enough to warrant explanation in the advisory rationale. Identify the differing features, derive market-supported adjustment values, apply them, and reconcile the adjusted prices into your advisory opinion of current market value.'
FROM scenario_categories WHERE code = 'M2-S4-C4';

