-- Scenario: 2619 Stonebridge Lane — Portfolio Disposition Advisory
-- Category M2-S4-C4 #3 · difficulty 'advanced'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 3,
  'advanced',
  '2619 Stonebridge Lane — Portfolio Disposition Advisory',
  'You are appraising a home at 2619 Stonebridge Lane, Greenville SC for a fee advisory engagement on behalf of Blue Ridge Asset Management. The client is liquidating part of a residential portfolio and needs a market value benchmark to establish the asking price. There is no contract price — the advisory opinion is the pricing anchor. The investor will use the conclusion as a listing benchmark and to set realistic price expectations.

The subject is a 2,250 SF home built in 2010 with three full bathrooms, a 2-car garage, in good condition, in a standard (non-amenitied) location. Three closed sales are provided, differing across four adjustment types: GLA, location, condition, and market conditions. The GLA paired sales include an outlier (Pair 4) that must be excluded with documented reasoning — a sophisticated asset management client will scrutinize the inputs. Comp 3 carries opposing-direction adjustments — Location is negative (Comp 3 is in an amenitied/gated community, superior) and Market Conditions is positive (Comp 3 sold 10 months ago, inferior). The investor client needs to understand that while the net adjustment for Comp 3 is small, the gross adjustment is substantial, and Comp 3 should therefore receive reduced weight in the final pricing recommendation. The cost-vs-market gap on GLA ($62.13/SF cost vs. ~$44/SF market) is directly actionable information for the investor — buyers do not pay replacement cost for additional square footage at this vintage. Identify the differing features, derive market-supported adjustment values, apply them independently, and reconcile into your advisory opinion of current market value with appropriate weighting commentary.'
FROM scenario_categories WHERE code = 'M2-S4-C4';

